#!/usr/bin/env node

/**
 * Validates all plugin manifests in the plugins/ directory.
 *
 * registry.json is auto-generated by CI — this script validates
 * the source of truth (manifests), not the generated index.
 *
 * Checks:
 * 1. Each plugin has a valid manifest.json
 * 2. Required manifest fields are present
 * 3. Manifest id matches directory name
 * 4. Entry points exist on disk
 * 5. Settings format is correct
 * 6. No duplicate plugin IDs
 */

const fs = require("fs");
const path = require("path");

const ROOT = path.resolve(__dirname, "..");
const PLUGINS_DIR = path.join(ROOT, "plugins");

const REQUIRED_MANIFEST_FIELDS = [
  "id",
  "name",
  "version",
  "description",
  "author",
  "minKrytonVersion",
];

let errors = 0;

function error(msg) {
  console.error(`  ERROR: ${msg}`);
  errors++;
}

function info(msg) {
  console.log(`  ${msg}`);
}

// --- Scan plugins/ directory ---

if (!fs.existsSync(PLUGINS_DIR)) {
  console.error("No plugins/ directory found");
  process.exit(1);
}

const pluginDirs = fs
  .readdirSync(PLUGINS_DIR, { withFileTypes: true })
  .filter((d) => d.isDirectory());

if (pluginDirs.length === 0) {
  console.log("No plugins found — nothing to validate");
  process.exit(0);
}

console.log(`Validating ${pluginDirs.length} plugin(s)...\n`);

const seenIds = new Set();

for (const dir of pluginDirs) {
  console.log(`Validating plugin: ${dir.name}...`);

  const pluginDir = path.join(PLUGINS_DIR, dir.name);
  const manifestPath = path.join(pluginDir, "manifest.json");

  // Check manifest exists
  if (!fs.existsSync(manifestPath)) {
    error(`Missing manifest.json in plugins/${dir.name}/`);
    continue;
  }

  // Parse manifest
  let manifest;
  try {
    const raw = fs.readFileSync(manifestPath, "utf-8");
    manifest = JSON.parse(raw);
  } catch (err) {
    error(`Failed to parse plugins/${dir.name}/manifest.json: ${err.message}`);
    continue;
  }

  // Check required fields
  for (const field of REQUIRED_MANIFEST_FIELDS) {
    if (!manifest[field]) {
      error(`plugins/${dir.name}/manifest.json missing required field: '${field}'`);
    }
  }

  // Check id matches directory name
  if (manifest.id && manifest.id !== dir.name) {
    error(`Manifest id '${manifest.id}' does not match directory name '${dir.name}'`);
  }

  // Check for duplicate IDs
  if (manifest.id) {
    if (seenIds.has(manifest.id)) {
      error(`Duplicate plugin ID: '${manifest.id}'`);
    }
    seenIds.add(manifest.id);
  }

  // Check at least one entry point
  if (!manifest.server && !manifest.client) {
    error(`Plugin '${dir.name}' must declare at least one of 'server' or 'client' entry points`);
  }

  // Check entry points exist on disk (TypeScript source or built JS)
  if (manifest.server) {
    const serverPath = path.join(pluginDir, manifest.server);
    const serverTsPath = serverPath.replace(/\.js$/, ".ts");
    if (!fs.existsSync(serverPath) && !fs.existsSync(serverTsPath)) {
      error(`Server entry point not found: plugins/${dir.name}/${manifest.server} (or .ts source)`);
    }
  }
  if (manifest.client) {
    const clientPath = path.join(pluginDir, manifest.client);
    const clientTsPath = clientPath.replace(/\.js$/, ".ts");
    if (!fs.existsSync(clientPath) && !fs.existsSync(clientTsPath)) {
      error(`Client entry point not found: plugins/${dir.name}/${manifest.client} (or .ts source)`);
    }
  }

  // Validate version format (semver-like)
  if (manifest.version && !/^\d+\.\d+\.\d+/.test(manifest.version)) {
    error(`Plugin '${dir.name}' version '${manifest.version}' is not valid semver`);
  }

  // Validate settings if present
  if (manifest.settings) {
    if (!Array.isArray(manifest.settings)) {
      error(`Plugin '${dir.name}' settings must be an array`);
    } else {
      for (const setting of manifest.settings) {
        if (!setting.key) {
          error(`Plugin '${dir.name}' has a setting without a 'key'`);
        }
        if (!setting.type || !["string", "boolean", "number"].includes(setting.type)) {
          error(`Plugin '${dir.name}' setting '${setting.key || "?"}' has invalid type (must be string, boolean, or number)`);
        }
        if (!setting.label) {
          error(`Plugin '${dir.name}' setting '${setting.key || "?"}' missing 'label'`);
        }
        if (setting.default === undefined) {
          error(`Plugin '${dir.name}' setting '${setting.key || "?"}' missing 'default'`);
        }
      }
    }
  }

  // Validate tags if present
  if (manifest.tags && !Array.isArray(manifest.tags)) {
    error(`Plugin '${dir.name}' tags must be an array`);
  }

  info(`OK - ${manifest.name || dir.name} v${manifest.version || "?"}`);
}

// --- Summary ---

console.log("");
if (errors > 0) {
  console.error(`Validation FAILED with ${errors} error(s)`);
  process.exit(1);
} else {
  console.log(`Validation PASSED - ${pluginDirs.length} plugin(s) valid`);
}
